import request from '@/utils/request'

export const user = {
  // 更新用户名
  updateUsername: (data) => {
    return request.post('/api/v1/users/account/username/', {
      username: data.username
    })
  },

  // 更换手机号
  changePhone: (data) => {
    return request.post('/api/v1/users/account/phone/', {
      phone: data.phone,
      code: data.code
    })
  },

  // 修改密码
  updatePassword: (data) => {
    return request.post('/api/v1/users/account/password/', {
      old_password: data.old_password,
      new_password: data.new_password,
      confirm_password: data.confirm_password
    })
  },

  // 删除账户
  deleteAccount: (data) => {
    return request.post('/api/v1/users/account/delete/', {
      password: data.password
    })
  },

  // 获取个人资料布局
  getProfileLayout: () => {
    return request.get('/api/v1/users/profile/layout/')
  },

  // 更新个人资料布局
  updateProfileLayout: (data) => {
    return request.post('/api/v1/users/profile/layout/', data)
  },

  // 获取个人资料数据
  getProfileData: () => {
    return request.get('/api/v1/users/profile/data/')
  },

  // 更新个人资料数据
  updateProfileData: (data) => {
    return request.post('/api/v1/users/profile/data/', data)
  },

  // 获取可用模块列表
  getAvailableModules: () => {
    return request.get('/api/v1/users/profile/layout/available/')
  },

  // 获取模块数据
  getModuleData: (moduleType) => {
    return request.get(`/api/v1/users/profile/layout/${moduleType}/`)
  },

  // 更新模块数据
  updateModuleData: (moduleType, data) => {
    return request.post(`/api/v1/users/profile/layout/${moduleType}/`, data)
  }
}

export default user
